// UUID direkt, Body base64. queryReplacement ist comma-separated; UUID hat keine Kommas.
const item = $input.first().json;
const id = (item.params && item.params.id) || '';
const body = item.body || {};
const body_b64 = Buffer.from(JSON.stringify(body), 'utf8').toString('base64');
return [{ json: { id, body_b64 } }];
